function toKebabCase(str: string): string {
  return str.replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase();
}

function formatFontStack(fonts: string[]): string {
  return fonts.map(f => f.includes(' ') ? `"${f}"` : f).join(', ');
